/* ===== 移动端整体适配 ===== */
@media (max-width: 768px) {
    /* 移动端隐藏 section332 区块 */
    .section332 {
        display: none !important;
    }

    /* 基础排版与容器内边距 */
    .hero-section {


        padding: 0.75rem 1rem;
        height: 100vh;

    }

    .hero-content {
        margin-left: 0;
        /* 仅移动端：为固定导航预留空间，避免被遮挡 */

        padding: 0 0.5rem;
        align-items: flex-start;
        margin-top: 5rem;
    }

    .hero-title {
        font-size: 1.25rem;
        line-height: 1.4;
    }

    .hero-main-title {
        font-size: 2.4rem;
        line-height: 1.25;
    }

    .hero-description {
        font-size: 1.3rem;
        line-height: 1.6;
        max-width: 100%;
    }

    .hero-subtitle {
        font-size: 1.2rem;
        line-height: 1.35;
        max-width: 100%;
    }

    .cta-buttons {
        gap: 0.75rem;
        flex-wrap: wrap;
        width: 100%;
    }

    .cta-primary,
    .cta-secondary {
        padding: 0.6rem 1rem;
        font-size: 0.95rem;
    }

    /* 移动端隐藏产品展示区域 */
    .product-showcase {
        display: none !important;
    }

    .product-container {
        justify-content: center;
    }

    .product-image {
        width: 100%;
        height: auto;
        border-radius: 12px;
    }

    /* 特性卡片栅格在小屏降为 1 列 */
    .feature-cards {
        width: 95%;
        padding: 0 0.5rem;
        margin-top: 5rem;
        margin-bottom: 16rem;
    }

    .features-grid {
        grid-template-columns: 1fr;
        gap: 1rem;
        padding: 1rem;
    }

    .feature-card.right {
        border-left: none;
